INSERT INTO signals.distress_events
  (parcel_id, event_type, event_subtype, event_date, event_value,
   source, source_id, severity, title, description, raw_data, observed_at)
SELECT
  i.parcel_id,
  'tax_delinquent',
  'delinquent_tax_list',
  DATE '2026-01-02',
  i.amount,
  'olmsted_delq_list',
  i.parcel_id,
  'medium',
  'On the 2026 Olmsted County Delinquent Tax List',
  'Real property on which taxes and penalties became delinquent on '
  || 'January 2, 2026, per the statutory Delinquent Tax List (Minn. '
  || 'Stat. ch. 279) published in the Rochester Post Bulletin on '
  || 'March 14, 2026. Interest accrues from January 1, 2026; the '
  || 'total tax and penalties must be paid for removal from the list.',
  i.raw,
  now()
FROM incoming i
WHERE EXISTS (SELECT 1 FROM core.parcels p
              WHERE p.parcel_id = i.parcel_id AND p.county_code = 'olmsted')
  AND NOT EXISTS (
    SELECT 1 FROM signals.distress_events de
    WHERE de.parcel_id = i.parcel_id
      AND de.event_type = 'tax_delinquent'
      AND de.event_date = DATE '2026-01-02'
      AND de.source = 'olmsted_delq_list');

-- Verification
SELECT COUNT(*) AS olmsted_delq_events,
       ROUND(SUM(event_value), 2) AS total_delinquency,
       COUNT(*) FILTER (WHERE (raw_data->>'ocr_pin_corrected')::boolean) AS ocr_corrected,
       MIN(event_value) AS min_amt, MAX(event_value) AS max_amt
FROM signals.distress_events
WHERE source = 'olmsted_delq_list';
